/*
 A length-counted byte buffer that crosses the boundary.

 When returned by a function it
 owns a Rust allocation; release it with [`aisd_bytes_free`] (or [`aisd_wire_message_free`]
 for the buffers inside an [`AisdWireMessage`]). An empty buffer is `{ ptr: null, len: 0,
 cap: 0 }`. When *passed in* (e.g. to [`aisd_wire_message_encode`]) only `ptr`/`len` are
 read and the buffer is borrowed, not freed.
 */
typedef struct AisdBytes {
    /*
     Pointer to `len` bytes, or null when `len == 0`.
     */
    uint8_t *ptr;
    /*
     Number of valid bytes at `ptr`.
     */
    size_t len;
    /*
     Allocation capacity (an implementation detail of the Rust owner; the caller must
     pass an [`AisdBytes`] back to the matching `*_free` unchanged).
     */
    size_t cap;
} AisdBytes;

/*
 A length-counted array of owned byte buffers that crosses the boundary (e.g. the parity shards
 from [`crate::video::aisd_fec_parity`]).

 When returned by a function it owns a Rust allocation: both the `items` array and every
 [`AisdBytes`] inside it. Release the whole thing with [`aisd_bytes_array_free`] — never C
 `free`, and never free an individual `items[i]` separately. An empty array is `{ items: null,
 count: 0 }`. Field order MUST match the C header's `AisdBytesArray`.
 */
typedef struct AisdBytesArray {
    /*
     Pointer to `count` owned [`AisdBytes`], or null when `count == 0`.
     */
    struct AisdBytes *items;
    /*
     Number of elements at `items`.
     */
    size_t count;
} AisdBytesArray;

/*
 Result of a fallible boundary call: `0` ok, `1` "needs more bytes", negative = error.
 */
typedef int32_t AisdStatus;

/*
 A decoded (or to-be-encoded) terminal-protocol message, flattened for the C ABI.

 `tag` selects which fields are meaningful — it equals the on-wire message type and one
 of the `AISD_WIRE_*` constants. Numeric fields are zero when not used by the tag; the
 variable-length `data` / `data2` buffers are [`AisdBytes::EMPTY`] when not used. After a
 successful [`aisd_frame_decoder_next`], release the buffers with [`aisd_wire_message_free`].

 Field usage by tag:
 * `OUTPUT`: `seq`, `data` (raw VT bytes)
 * `EXIT`: `code`
 * `INPUT`: `data` (stdin bytes)
 * `HELLO`: `protocol_version`, `session_id`, `last_received_seq`
 * `RESIZE`: `cols`, `rows`, `px_width`, `px_height`
 * `ACK`: `seq`
 * `BYE` / `BELL`: (none)
 * `PING` / `PONG`: `timestamp_ms`
 * `HELLO_ACK`: `session_id`, `resume_from_seq`, `returning_client`
 * `TITLE`: `data` (UTF-8)
 * `COMMAND_STATUS`: `cmd_running`; if idle, `cmd_has_exit_code` + `code` + `duration_ms`
 * `NOTIFICATION`: `data` (UTF-8 title), `data2` (UTF-8 body)
 */
typedef struct AisdWireMessage {
    /*
     Message type; equals one of the `AISD_WIRE_*` constants.
     */
    uint8_t tag;
    /*
     `OUTPUT.seq` / `ACK.seq` — monotonic per-message index.
     */
    int64_t seq;
    /*
     `EXIT.code`, or the idle `COMMAND_STATUS` exit code (valid iff `cmd_has_exit_code`).
     */
    int32_t code;
    /*
     `HELLO.protocol_version`.
     */
    uint16_t protocol_version;
    /*
     `HELLO.last_received_seq`.
     */
    int64_t last_received_seq;
    /*
     `HELLO_ACK.resume_from_seq`.
     */
    int64_t resume_from_seq;
    /*
     `RESIZE.cols` (character cells).
     */
    uint16_t cols;
    /*
     `RESIZE.rows` (character cells).
     */
    uint16_t rows;
    /*
     `RESIZE.px_width` (0 if unknown).
     */
    uint16_t px_width;
    /*
     `RESIZE.px_height` (0 if unknown).
     */
    uint16_t px_height;
    /*
     `PING.timestamp_ms` / `PONG.timestamp_ms`.
     */
    uint64_t timestamp_ms;
    /*
     `HELLO_ACK.returning_client` — `0` = false, any nonzero = true. (A plain byte, not a
     Rust `bool`, so a C/JNI caller storing e.g. a `jboolean` of `2` is read as `!= 0`
     rather than triggering `bool`-validity UB.)
     */
    uint8_t returning_client;
    /*
     `HELLO` / `HELLO_ACK` 16-byte session id (all-zero requests a new session).
     */
    uint8_t session_id[16];
    /*
     `COMMAND_STATUS`: nonzero = running, `0` = idle (a byte, read as `!= 0`).
     */
    uint8_t cmd_running;
    /*
     Idle `COMMAND_STATUS`: nonzero if `code` carries a reported exit status (read as `!= 0`).
     */
    uint8_t cmd_has_exit_code;
    /*
     Idle `COMMAND_STATUS`: host-measured command wall-clock time in milliseconds.
     */
    uint32_t duration_ms;
    /*
     Primary variable-length payload (see per-tag usage above).
     */
    struct AisdBytes data;
    /*
     Secondary variable-length payload (`NOTIFICATION` body only).
     */
    struct AisdBytes data2;
} AisdWireMessage;

/*
 A borrowed view of a DATA-channel payload (`Output`/`Input`) for the zero-copy decode path.

 `bytes` points INTO the caller-supplied payload buffer (it is NOT owned and must NOT be freed);
 it is valid only for as long as that buffer lives. `tag` is `1` (output) or `3` (input) for a
 DATA frame, or `0` when the payload is a control message the caller must decode through
 [`aisd_wire_message_decode`]. Field order MUST match the C header's `AisdDataFrameView`.
 */
typedef struct AisdDataFrameView {
    /*
     `1` = output, `3` = input, `0` = not a DATA frame (use the owned decode).
     */
    uint8_t tag;
    /*
     `Output.seq` (`0` for input or a non-DATA frame).
     */
    int64_t seq;
    /*
     Borrowed bulk payload bytes (null when empty), pointing into the input payload.
     */
    const uint8_t *bytes;
    /*
     Number of bytes at `bytes`.
     */
    size_t bytes_len;
} AisdDataFrameView;

/*
 Tier-decision state for the dwell-gated adaptive-FEC variant, flattened for the C ABI.

 Mirrors [`adaptive_fec::TierState`] field-for-field (`#[repr(C)]`, same field order). Crosses
 by value in both directions.
 */
typedef struct AisdTierState {
    /*
     Current wire tier (0..=7 on the wire; any `u8` is total).
     */
    uint8_t tier;
    /*
     Consecutive reports that demanded relaxation.
     */
    int32_t relax_streak;
    /*
     Reports remaining in the sticky-relax (doubled-dwell) window; 0 = inactive.
     */
    int32_t sticky_relax_remaining;
} AisdTierState;

