void aisd_pacer_depth_policy_note_network_late(struct AisdPacerDepthPolicy *policy, double now);

/*
 Folds one empty re-show at `now`. No-op on null. Wraps [`PacerDepthPolicy::note_reshow`].

 # Safety
 `policy`, if non-null, must be a live handle.
 */
void aisd_pacer_depth_policy_note_reshow(struct AisdPacerDepthPolicy *policy, double now);

/*
 Drains (and resets) the windowed counters. Returns `{0, 0}` for a null handle. Wraps
 [`PacerDepthPolicy::drain_counters`].

 # Safety
 `policy`, if non-null, must be a live handle.
 */
struct AisdPacerCounters aisd_pacer_depth_policy_drain_counters(struct AisdPacerDepthPolicy *policy);

/*
 Sets (or clears) the FPS-governor interval hint. `has_hint == 0` clears it; otherwise the hint is
 `seconds`. No-op on null. Wraps [`PacerDepthPolicy::set_interval_hint`].

 # Safety
 `policy`, if non-null, must be a live handle.
 */
void aisd_pacer_depth_policy_set_interval_hint(struct AisdPacerDepthPolicy *policy,
                                               double seconds,
                                               uint8_t has_hint);

/*
 Builds a packetizer that appends `m` parity shards per group of `k` data fragments.

 The packetizer OWNS a freshly-built NEON-backed Reed-Solomon codec (`[k + m, k]`) — there is no
 externally-supplied FEC handle and therefore no double-codec (mirroring [`aisd_reassembler_new`]
 on the receive side). `m == 1` is the production wire (XOR-equivalent, byte-identical). Pass
 `k == 0` (or `m == 0`) to build a NO-FEC packetizer (no parity fragments) — mirroring
 `VideoPacketizer(fec: nil)`.

 Returns null (NOT a panic/abort across the boundary) for an invalid FEC config: `k >= 1` but
 `m >= 1` with `k + m > 255` (the Cauchy index sets must fit GF(2^8)). Destroy a non-null result
 with [`aisd_video_packetizer_free`].

 [`aisd_reassembler_new`]: super::reassembler::aisd_reassembler_new
 */
struct AisdVideoPacketizer *aisd_video_packetizer_new(size_t k, size_t m);

/*
 Destroys a packetizer created by [`aisd_video_packetizer_new`]. No-op on null.

 # Safety
 `packetizer` must be a pointer from [`aisd_video_packetizer_new`] that has not been freed.
 */
void aisd_video_packetizer_free(struct AisdVideoPacketizer *packetizer);

/*
 The `frame_id` the NEXT [`aisd_packetize`] call will assign (0 for a null handle).

 The host actor reads this BEFORE packetizing so it can record the `frame_id ↔ LTR-token` mapping
 (and the recovery-IDR keyframe record) for the frame about to be sent — `packetize` increments
 the counter internally, exactly like the Swift `peekNextFrameID`.

 # Safety
 `packetizer`, if non-null, must be a live handle from [`aisd_video_packetizer_new`].
 */
uint32_t aisd_video_packetizer_peek_next_frame_id(const struct AisdVideoPacketizer *packetizer);

/*
 The `stream_seq` the next emitted datagram will carry (0 for a null handle).

 # Safety
 `packetizer`, if non-null, must be a live handle from [`aisd_video_packetizer_new`].
 */
uint32_t aisd_video_packetizer_peek_next_stream_seq(const struct AisdVideoPacketizer *packetizer);

/*
 Fragments one AVCC frame into fully-formed wire datagrams, writing them to `*out_fragments`.

 `avcc` is the encoded frame's AVCC bytes (length-prefixed NAL units), BORROWED — read, never
 freed; `avcc` may be null only when `avcc_len == 0` (a zero-byte frame still yields one fragment).
 `opts` crosses by value. On [`AISD_OK`], `*out_fragments` owns an [`AisdBytesArray`] of one
 fragment per datagram, each already the complete wire bytes (19-byte header + payload), in
 transmit order (data fragments, then parity; column-major when `opts.interleave != 0`). Release
 the whole array with [`crate::aisd_bytes_array_free`].

 The packetizer assigns the per-frame `frame_id` and the monotonic per-datagram `stream_seq`
 internally, and runs the FEC parity through its OWNED codec (no double-FEC). The per-frame group
 size is `opts.fec_group_size` (or the codec's default `k` when `0`); the interleave is keyed by
 the same size (m-aware), so the `m == 1` send order is byte-identical to the pre-port wire.

 Returns [`AISD_ERR_NULL`] for a null `packetizer` / `out_fragments` (or a null `avcc` with a
 nonzero `avcc_len`), else [`AISD_OK`]. NEVER panics: the only failure is a null argument; an
 empty frame yields a single one-fragment array.

 # Safety
 `out_fragments` must be a writable [`AisdBytesArray`]; if `avcc_len != 0`, `avcc` must point to
 at least `avcc_len` readable bytes. On [`AISD_OK`] `*out_fragments` is overwritten as raw output
 WITHOUT freeing any prior contents, so release a previously-returned array held in the same
 storage with [`crate::aisd_bytes_array_free`] first (or use fresh storage) to avoid leaking it.
 */
AisdStatus aisd_packetize(struct AisdVideoPacketizer *packetizer,
                          const uint8_t *avcc,
                          size_t avcc_len,
                          struct AisdPacketizeOptions opts,
                          struct AisdBytesArray *out_fragments);

/*
 Reorders already-encoded wire fragments into burst-resilient transmit order, m-aware.

 The standalone counterpart of the `opts.interleave` knob in [`aisd_packetize`] — for callers that
 hold the fully-encoded datagrams and want only the column-major reorder (e.g. the host's
 `FragmentInterleaver` API and the loopback validator). Each element of `fragments` is a BORROWED
 wire datagram (19-byte header + payload); they are parsed, reordered by [`interleave`] (data
 column-major across FEC groups, then parity column-major across groups — `m` recovered from the
 parity count), and the reordered datagrams returned as one owned [`AisdBytesArray`] (release with
 [`crate::aisd_bytes_array_free`]). NO wire change: only the SEND ORDER differs; each datagram's
 bytes (header + payload) are byte-identical to the input. `group_size <= 1` (or too few fragments)
 is a no-op pass-through, byte-for-byte.

 Returns [`AISD_ERR_NULL`] for a null `fragments` (with a nonzero `count`) / `out`. NEVER panics:
 a datagram that fails to parse is dropped from the reorder set (a corrupt fragment never crashes
 the send loop), so the output is always a valid owned array.

 # Safety
 `out` must be writable; if `count != 0`, `fragments` must point to `count` readable [`AisdBytes`],
 each whose non-empty `(ptr, len)` covers `len` readable bytes for the call. On [`AISD_OK`] `*out`
 is overwritten as raw output WITHOUT freeing prior contents (release a prior array first).
 */
AisdStatus aisd_interleave(const struct AisdBytes *fragments,
                           size_t count,
                           size_t group_size,
                           struct AisdBytesArray *out);

/*
 Builds a reassembler that recovers up to `m` losses per group of `k` data fragments, granting a
 reorder grace of `fec_reorder_grace` frame-ids past the loss frontier for awaited parity.

 The reassembler OWNS a freshly-built NEON-backed Reed-Solomon codec (`[k + m, k]`) — there is no
 externally-supplied FEC handle and therefore no double-codec. `m == 1` is the production wire
 (XOR-equivalent, byte-identical). Pass `k == 0` (or `m == 0`) to build a NO-FEC reassembler (a
 missing data fragment is then terminal once the frame is old) — mirroring `FrameReassembler(fec:
 nil)`.

 Returns null (NOT a panic/abort across the boundary) for an invalid FEC config: `k >= 1` but
 `m < 1`, or `k + m > 255` (the Cauchy index sets must fit GF(2^8)). `fec_reorder_grace` is
 floored at 0 by the core. Destroy a non-null result with [`aisd_reassembler_free`].
 */
struct AisdReassembler *aisd_reassembler_new(size_t k, size_t m, int32_t fec_reorder_grace);

/*
 Destroys a reassembler created by [`aisd_reassembler_new`]. No-op on null.

 # Safety
 `reassembler` must be a pointer from [`aisd_reassembler_new`] that has not been freed.
 */
void aisd_reassembler_free(struct AisdReassembler *reassembler);

/*
 Parses and ingests one fragment datagram, writing the outcome to `*out`.

 `datagram` is the raw 19-byte header + payload (BORROWED — read, never freed); `datagram` may be
 null only when `len == 0`. On a COMPLETED frame, `out.avcc` owns a Rust buffer — release it with
 [`crate::aisd_bytes_free`] (or the whole result with [`aisd_reassembly_result_free`]).

 Returns [`AISD_ERR_NULL`] for a null `reassembler` / `out` (or a null `datagram` with a nonzero
 `len`), else [`AISD_OK`] with `*out` populated. NEVER panics on hostile input: a datagram that
 fails to parse (truncated header, payload shorter than its declared length) OR whose header is
 degenerate (`frag_count == 0`, `frag_count` above the core guard, or `frag_index >= frag_count`)
 surfaces as [`AISD_REASSEMBLY_PENDING`] with an empty `avcc` — the datagram is ignored, never a
 crash and never a wedged buffer.

 # Safety
 `out` must be a writable [`AisdReassemblyResult`]; if `len != 0`, `datagram` must point to at
 least `len` readable bytes. On [`AISD_OK`] `*out` is overwritten as raw output WITHOUT freeing
 any prior contents, so a previously-completed result held in the same storage must be released
 with [`aisd_reassembly_result_free`] first (or use fresh storage) to avoid leaking its `avcc`.
 */
AisdStatus aisd_reassembler_ingest(struct AisdReassembler *reassembler,
                                   const uint8_t *datagram,
                                   size_t len,
                                   struct AisdReassemblyResult *out);

/*
 Pops the next unrecoverably-lost frame id detected by a PRIOR ingest's hopeless sweep.

 Returns `1` and writes `*out_frame_id` when a drop was surfaced, else `0` (`*out_frame_id`
 untouched). The caller drains this in a loop after each ingest and issues one recovery signal
 per id. Returns `0` for a null `reassembler` / `out_frame_id`.

 # Safety
 `out_frame_id`, if the call returns `1`, is written; it must be a writable `u32` pointer when
 non-null.
 */
uint8_t aisd_reassembler_next_dropped(struct AisdReassembler *reassembler, uint32_t *out_frame_id);

/*
 Releases the owned `avcc` buffer inside an [`AisdReassemblyResult`] and resets it to empty.

 A convenience over [`crate::aisd_bytes_free`] that also clears the discriminant. Idempotent (a
 second call is a no-op) and safe on a `PENDING` / `STALE` / zeroed result (its `avcc` is already
 [`AisdBytes::EMPTY`]); a null `result` pointer is also a no-op.

 # Safety
 `result`, if non-null, must point to a writable [`AisdReassemblyResult`] previously written by
 [`aisd_reassembler_ingest`] (or zeroed) and not already freed.
 */
void aisd_reassembly_result_free(struct AisdReassemblyResult *result);

/*
 Encodes a caller-built [`AisdRecoveryMessage`] into its wire form.

 On [`AISD_OK`], `*out` owns the buffer — release with [`crate::aisd_bytes_free`]. Returns
 [`AISD_ERR_NULL`] for a null argument or [`AISD_ERR_INVALID_ARGUMENT`] for an unknown `kind`.

 # Safety
 `msg` and `out` must be valid, writable pointers.
 */
AisdStatus aisd_recovery_message_encode(const struct AisdRecoveryMessage *msg,
                                        struct AisdBytes *out);

/*
 Decodes a recovery message into `*out`.

 `data` may be null only when `len == 0`. Maps an unknown type / trailing bytes to
 [`crate::AISD_ERR_MALFORMED`] and a short body to [`crate::AISD_ERR_TRUNCATED`]. The output is
 all-scalar (no owned buffer), so there is no `*_free`.

 # Safety
 `out` must be writable; if `len != 0`, `data` must point to `len` readable bytes.
 */
AisdStatus aisd_recovery_message_decode(const uint8_t *data,
                                        size_t len,
                                        struct AisdRecoveryMessage *out);

/*
 Creates a recovery-IDR policy from the resolved config scalars. Destroy it with
 [`aisd_recovery_idr_policy_free`].

 The seven scalars are the already-env-resolved [`RecoveryIdrConfig`] fields (the core stays
 env-free; the caller resolves `AISLOPDESK_IDR_*` Swift-side). Wraps [`RecoveryIdrPolicy::new`].
 */
struct AisdRecoveryIdrPolicy *aisd_recovery_idr_policy_new(double grace_fraction,
                                                           double grace_floor_seconds,
                                                           double grace_ceil_seconds,
                                                           double bucket_capacity,
                                                           double refill_tokens_per_second,
                                                           double grant_pending_timeout,
                                                           size_t keyframe_ring_capacity);

/*
 Destroys a policy created by [`aisd_recovery_idr_policy_new`]. No-op on null.

 # Safety
 `policy` must be a pointer from [`aisd_recovery_idr_policy_new`] that has not been freed.
 */
void aisd_recovery_idr_policy_free(struct AisdRecoveryIdrPolicy *policy);

/*
 The current token-bucket level (observability / tests), or `0.0` for a null handle.

 # Safety
 `policy`, if non-null, must be a live handle.
 */
double aisd_recovery_idr_policy_available_tokens(const struct AisdRecoveryIdrPolicy *policy);

/*
 Records that a keyframe was handed to the wire at `now`. No-op on null. Wraps
 [`RecoveryIdrPolicy::note_keyframe_sent`].

 # Safety
 `policy`, if non-null, must be a live handle.
 */
void aisd_recovery_idr_policy_note_keyframe_sent(struct AisdRecoveryIdrPolicy *policy,
                                                 uint32_t frame_id,
                                                 double now);

/*
 Records that the client decode-ACKed a keyframe. No-op on null. Wraps
 [`RecoveryIdrPolicy::note_keyframe_delivered`].

 # Safety
 `policy`, if non-null, must be a live handle.
 */
void aisd_recovery_idr_policy_note_keyframe_delivered(struct AisdRecoveryIdrPolicy *policy,
                                                      uint32_t frame_id);

/*
 The admission decision for one IDR-issuing recovery request, as an `AISD_RECOVERY_IDR_*`
 discriminant.

 `has_client_last_decoded == 0` ⇒ the wire sentinel "nothing decoded yet" (`client_last_decoded`
 is then ignored). Returns Grant (`0`) for a null handle (recovery proceeds rather than
 wedging). Wraps [`RecoveryIdrPolicy::decide`].

 # Safety
 `policy`, if non-null, must be a live handle.
 */
uint8_t aisd_recovery_idr_policy_decide(struct AisdRecoveryIdrPolicy *policy,
                                        double now,
                                        uint32_t client_last_decoded,
                                        uint8_t has_client_last_decoded,
                                        double smoothed_rtt_seconds);

/*
 The in-flight grace window (seconds) for the given smoothed RTT, or `0.0` for a null handle.
 Wraps [`RecoveryIdrPolicy::grace`].

 # Safety
 `policy`, if non-null, must be a live handle.
 */
double aisd_recovery_idr_policy_grace(const struct AisdRecoveryIdrPolicy *policy, double rtt);

/*
 Whether the client should escalate a stalled LTR-refresh recovery to a forced IDR,

 given
 the configured policy multiples, time since the first request, the RTT estimate, and
 whether it is observing loss.

 Wraps [`RecoveryPolicy::should_escalate_to_idr`].

 `observing_loss` crosses as a byte read `!= 0`. The lossy escalation floor (`lossy_floor_s`,
 from `AISLOPDESK_ESCALATION_FLOOR_MS`) is resolved by the caller and passed in, keeping the
 core environment-free. Returns `1` to escalate, `0` otherwise. The four multiples map
 field-for-field onto [`RecoveryPolicy`].
 */
uint8_t aisd_recovery_policy_should_escalate_to_idr(double idr_rtt_mult,
                                                    double lossy_idr_rtt_mult,
                                                    double lossy_floor_s,
                                                    double lossy_floor_rtt_mult,
                                                    double elapsed_since_request,
                                                    double rtt,
                                                    uint8_t observing_loss);

/*
 Creates a recovery-request deduper. Destroy it with [`aisd_recovery_deduper_free`].

 `window_seconds` drops duplicates for that long after the first sighting (`0` ⇒ always admit);
 `capacity` is the ring size (floored to 1). Wraps [`RecoveryRequestDeduper::new`].
 */
struct AisdRecoveryDeduper *aisd_recovery_deduper_new(double window_seconds, size_t capacity);

/*
 Destroys a deduper created by [`aisd_recovery_deduper_new`]. No-op on null.

 # Safety
 `deduper` must be a pointer from [`aisd_recovery_deduper_new`] that has not been freed.
 */
void aisd_recovery_deduper_free(struct AisdRecoveryDeduper *deduper);

/*
 Admits a recovery-request datagram. Wraps [`RecoveryRequestDeduper::admit`].

 Returns `1` = first sighting within the window (the caller should process it), `0` = a
 byte-identical duplicate (the caller should drop it).

 FAIL-OPEN: a null handle, or a null `datagram` with a nonzero `len`, returns `1` (process) —
 never `0` — so a caller bug degrades to the pre-dedup "act on every copy" behaviour rather than
 silently swallowing a real recovery request. `datagram` may be null only when `len == 0` (an
 empty datagram admits normally).

 # Safety
 `deduper` must be a live handle; if `len != 0`, `datagram` must point to at least `len`
 readable bytes.
 */
uint8_t aisd_recovery_deduper_admit(struct AisdRecoveryDeduper *deduper,
                                    const uint8_t *datagram,
                                    size_t len,
                                    double now);

/*
 Creates a scroll reprojector from the resolved config (zero offset / zero velocity). Destroy it
 with [`aisd_scroll_reprojector_free`]. Wraps [`ScrollReprojector::new`].
 */
struct AisdScrollReprojector *aisd_scroll_reprojector_new(struct AisdScrollReprojectorConfig config);

/*
 Destroys a reprojector created by [`aisd_scroll_reprojector_new`]. No-op on null.

 # Safety
 `reprojector` must be a pointer from [`aisd_scroll_reprojector_new`] that has not been freed.
 */
void aisd_scroll_reprojector_free(struct AisdScrollReprojector *reprojector);

/*
 Folds one scroll-velocity sample (`vx`/`vy` in normalized units per second) with its
 `AISD_SCROLL_PHASE_*` phase. No-op on null. Wraps [`ScrollReprojector::note_velocity`].

 # Safety
 `reprojector`, if non-null, must be a live handle.
 */
void aisd_scroll_reprojector_note_velocity(struct AisdScrollReprojector *reprojector,
                                           double vx,
                                           double vy,
                                           uint8_t phase);

/*
 Integrates over `elapsed_seconds` (or decays a stopped scroll), clamps, and writes the offset.

 The resulting offset goes into `*out_x` / `*out_y`. Returns [`AISD_ERR_NULL`] for a null handle
 or a null out-param (the out-params are left untouched), else [`crate::AISD_OK`]. Wraps
 [`ScrollReprojector::advance`].

 # Safety
 `reprojector`, if non-null, must be a live handle; `out_x` / `out_y` must be writable, non-null
 pointers.
 */
AisdStatus aisd_scroll_reprojector_advance(struct AisdScrollReprojector *reprojector,
                                           double elapsed_seconds,
                                           double *out_x,
                                           double *out_y);

/*
 Resets the offset (and integration baseline) to exactly zero (the no-double-count reset).

 Call the instant a real decoded frame is presented so the hint is never added on top of the
 real scroll. The live velocity is preserved. No-op on null. Wraps
 [`ScrollReprojector::note_real_frame`].

 # Safety
 `reprojector`, if non-null, must be a live handle.
 */
void aisd_scroll_reprojector_note_real_frame(struct AisdScrollReprojector *reprojector);

/*
 Fully resets the reprojector (offset AND velocity to zero) — call when a pane goes idle / loses
 focus so a stale velocity can never resume. No-op on null. Wraps [`ScrollReprojector::reset`].

 # Safety
 `reprojector`, if non-null, must be a live handle.
 */
void aisd_scroll_reprojector_reset(struct AisdScrollReprojector *reprojector);

/*
 Creates a static-IDR decider. Destroy it with [`aisd_static_idr_decider_free`].

 `heartbeat` is the cadence in seconds. `has_quiet_window != 0` sets the quiet window to
 `quiet_window`; otherwise the core default (one cadence = `heartbeat`) is used. Wraps
 [`StaticIDRDecider::new`].
 */
struct AisdStaticIdrDecider *aisd_static_idr_decider_new(double heartbeat,
                                                         double quiet_window,
                                                         uint8_t has_quiet_window);

/*
 Destroys a decider created by [`aisd_static_idr_decider_new`]. No-op on null.

 # Safety
 `decider` must be a pointer from [`aisd_static_idr_decider_new`] that has not been freed.
 */
void aisd_static_idr_decider_free(struct AisdStaticIdrDecider *decider);

/*
 The configured heartbeat cadence (seconds), or `0.0` for a null handle.

 # Safety
 `decider`, if non-null, must be a live handle.
 */
double aisd_static_idr_decider_heartbeat(const struct AisdStaticIdrDecider *decider);

/*
 The configured quiet window (seconds), or `0.0` for a null handle.

 # Safety
 `decider`, if non-null, must be a live handle.
 */
double aisd_static_idr_decider_quiet_window(const struct AisdStaticIdrDecider *decider);

/*
 Uptime seconds of the last REAL `.complete`-frame encode (`0.0` = none / null handle).

 # Safety
 `decider`, if non-null, must be a live handle.
 */
double aisd_static_idr_decider_last_complete_encode(const struct AisdStaticIdrDecider *decider);

/*
 Uptime seconds of the last SYNTHETIC re-encode (`0.0` = none / null handle).

 # Safety
 `decider`, if non-null, must be a live handle.
 */
double aisd_static_idr_decider_last_synthetic_encode(const struct AisdStaticIdrDecider *decider);

/*
 Re-anchors the live clock: a REAL `.complete` frame was encoded at `now`. No-op on null.
 Wraps [`StaticIDRDecider::on_complete_frame`].

 # Safety
 `decider`, if non-null, must be a live handle.
 */
void aisd_static_idr_decider_on_complete_frame(struct AisdStaticIdrDecider *decider, double now);

/*
 Re-anchors the synthetic clock: the timer fired a synthetic re-encode at `now`. No-op on null.
 Wraps [`StaticIDRDecider::record_synthetic`].

 # Safety
 `decider`, if non-null, must be a live handle.
 */
void aisd_static_idr_decider_record_synthetic(struct AisdStaticIdrDecider *decider, double now);

/*
 Whether the caller should re-encode the cached buffer as a forced IDR now.

 Wraps [`StaticIDRDecider::should_reencode`]. `forced_latched` / `has_retained_buffer` are
 bytes read `!= 0`. Returns `1` to re-encode, `0` otherwise (and `0` for a null handle — a
 missing decider never forces an encode).

 # Safety
 `decider`, if non-null, must be a live handle.
 */
uint8_t aisd_static_idr_decider_should_reencode(const struct AisdStaticIdrDecider *decider,
                                                double now,
                                                uint8_t forced_latched,
                                                uint8_t has_retained_buffer);

/*
 The minimum on-screen width/height (points) for a window to be a surfaced system dialog. Wraps
 [`system_dialog_detector::MIN_SIZE`].
 */
int64_t aisd_system_dialog_min_size(void);

/*
 Classifies ONE on-screen window into a surfaced system dialog.

 Wraps [`system_dialog_detector::classify`]: the secure/system allowlists and the on-screen +
 min-size rules live ONLY in the core. The three strings are borrowed for the call (each may be
 null only when its length is `0`). Returns [`AISD_OK`] (a dialog was written to `*out` — release
 its `owner` / `title` with [`aisd_system_dialog_free`]), [`AISD_EMPTY`] (not a system dialog;
 nothing written), or [`AISD_ERR_NULL`] (a null `out`, or a null string with a nonzero length).

 # Safety
 `out` must be a writable [`AisdSystemDialog`]; each non-empty string must point to that many
 readable bytes. On a non-[`AISD_OK`] return `*out` is untouched; on [`AISD_OK`] it is
 overwritten as raw output WITHOUT freeing prior contents.
 */
AisdStatus aisd_system_dialog_classify(uint32_t window_id,
                                       const uint8_t *owner_name,
                                       size_t owner_name_len,
                                       const uint8_t *bundle_id,
                                       size_t bundle_id_len,
                                       uint8_t is_on_screen,
                                       const uint8_t *title,
                                       size_t title_len,
                                       struct AisdRect frame,
                                       int64_t min_size,
                                       struct AisdSystemDialog *out);

/*
 Releases the owned `owner` / `title` buffers inside an [`AisdSystemDialog`] and resets them to
 empty. Idempotent; the struct itself is caller-owned.

 # Safety
 `msg` must point to a writable [`AisdSystemDialog`] previously filled by this library.
 */
void aisd_system_dialog_free(struct AisdSystemDialog *msg);

/*
 Encodes a caller-built [`AisdVideoControl`] into its wire form.

 On [`AISD_OK`], `*out` owns the buffer — release with [`crate::aisd_bytes_free`]. Returns
 [`AISD_ERR_NULL`] for a null argument or [`AISD_ERR_INVALID_ARGUMENT`] for an unknown `kind`
 / non-UTF-8 record string.

 # Safety
 `msg` and `out` must be valid, writable pointers; for a list `kind`, a non-empty `records`
 inside `*msg` must point to that many readable [`AisdVideoSummary`] values.
 */
AisdStatus aisd_video_control_encode(const struct AisdVideoControl *msg, struct AisdBytes *out);

/*
 Decodes a video control message into `*out`.

 On [`AISD_OK`], `*out` may own a `records` array — release with [`aisd_video_control_free`].
 `data` may be null only when `len == 0`. Maps a non-finite coordinate / unknown type to
 [`crate::AISD_ERR_MALFORMED`] and a short body to [`crate::AISD_ERR_TRUNCATED`] (record strings
 decode lossily, never malformed).

 # Safety
 `out` must be writable; if `len != 0`, `data` must point to `len` readable bytes. On a
 non-[`AISD_OK`] return `*out` is untouched; on [`AISD_OK`] it is overwritten as raw output
 WITHOUT freeing prior contents.
 */
AisdStatus aisd_video_control_decode(const uint8_t *data, size_t len, struct AisdVideoControl *out);

/*
 Releases the owned `records` array inside an [`AisdVideoControl`] (and every record's `name` /
 `title` buffer) and resets it to empty. Idempotent; the struct itself is caller-owned.

 # Safety
 `msg` must point to a writable [`AisdVideoControl`] previously filled by this library.
 */
void aisd_video_control_free(struct AisdVideoControl *msg);

/*
 Creates a fresh mux router (nothing admitted). Destroy it with [`aisd_video_mux_router_free`].
 */
struct AisdVideoMuxRouter *aisd_video_mux_router_new(void);

/*
 Destroys a router created by [`aisd_video_mux_router_new`]. No-op on null.

 # Safety
 `router` must be a pointer from [`aisd_video_mux_router_new`] that has not been freed.
 */
void aisd_video_mux_router_free(struct AisdVideoMuxRouter *router);

/*
 Admits `channel_id` as a live lane (clears any retired/draining mark). No-op on null. Wraps
 [`VideoMuxRouter::admit`].

 # Safety
 `router`, if non-null, must be a live handle.
 */
void aisd_video_mux_router_admit(struct AisdVideoMuxRouter *router, uint32_t channel_id);

/*
 Retires `channel_id` (reconnect/teardown). No-op on null. Wraps [`VideoMuxRouter::retire`].

 # Safety
 `router`, if non-null, must be a live handle.
 */
void aisd_video_mux_router_retire(struct AisdVideoMuxRouter *router, uint32_t channel_id);

/*
 Begins draining `channel_id` on the reaper path. No-op on null. Wraps
 [`VideoMuxRouter::begin_drain`].

 # Safety
 `router`, if non-null, must be a live handle.
 */
void aisd_video_mux_router_begin_drain(struct AisdVideoMuxRouter *router, uint32_t channel_id);

/*
 Finishes draining `channel_id` (draining → retired). No-op on null. Wraps
 [`VideoMuxRouter::end_drain`].

 # Safety
 `router`, if non-null, must be a live handle.
 */
void aisd_video_mux_router_end_drain(struct AisdVideoMuxRouter *router, uint32_t channel_id);

/*
 Whether `channel_id` is an admitted (routable) lane. `0` for a null handle. Wraps
 [`VideoMuxRouter::is_admitted`].

 # Safety
 `router`, if non-null, must be a live handle.
 */
uint8_t aisd_video_mux_router_is_admitted(const struct AisdVideoMuxRouter *router,
                                          uint32_t channel_id);

/*
 Whether `channel_id` is currently draining. `0` for a null handle. Wraps
 [`VideoMuxRouter::is_draining`].

 # Safety
 `router`, if non-null, must be a live handle.
 */
uint8_t aisd_video_mux_router_is_draining(const struct AisdVideoMuxRouter *router,
                                          uint32_t channel_id);

/*
 The routing decision for one received datagram, as an `AISD_MUX_DECISION_*` discriminant.

 `channel` is a [`MuxVideoChannel`] raw byte (0=control … 5=recovery). Returns `RejectUnadmitted`
 (`1`) for a null handle (an unknown lane — the safe drop). Wraps [`VideoMuxRouter::route`].

 # Safety
 `router`, if non-null, must be a live handle.
 */
uint8_t aisd_video_mux_router_route(const struct AisdVideoMuxRouter *router,
                                    uint32_t channel_id,
                                    uint8_t channel,
                                    size_t bytes_count);

/*
 The bootstrap action for a not-yet-admitted datagram, as an `AISD_MUX_BOOTSTRAP_*` discriminant.

 `decision` is an `AISD_MUX_DECISION_*` value, `channel` a [`MuxVideoChannel`] raw byte;
 `payload_is_hello` / `payload_is_list_request` are bytes read `!= 0`. PURE (no handle). Wraps
 [`VideoMuxRouter::bootstrap_action`].
 */
uint8_t aisd_video_mux_router_bootstrap_action(uint8_t decision,
                                               uint8_t channel,
                                               uint8_t payload_is_hello,
                                               uint8_t payload_is_list_request);

/*
 Builds a (clamped) virtual-display geometry and returns its derived scalar fields. Wraps
 [`VirtualDisplayGeometry::new`]. Pure; never fails.
 */
struct AisdVDGeometry aisd_vd_geometry(int64_t point_width,
                                       int64_t point_height,
                                       int64_t scale,
                                       int64_t max_horizontal_pixels);

/*
 Physical size in millimetres for a display of `pixel_width × pixel_height` at `target_ppi`
 (non-finite / `< 1` ppi is clamped to `1.0`). Wraps
 [`VirtualDisplayGeometry::size_in_millimeters`].

 Built with `scale = 1` so the geometry's pixel dimensions equal the inputs verbatim,
 preserving the exact `(pixel / ppi) * 25.4` op order for bit parity.
 */
struct AisdVDMillimeters aisd_vd_size_in_millimeters(int64_t pixel_width,
                                                     int64_t pixel_height,
                                                     double target_ppi);

/*
 The VD global origin flush to the right of the rightmost existing display.

 Returns (`maxX`, `0`), or `(0, 0)` when there are no displays. Wraps
 [`virtual_display_geometry::origin_to_right`]. `displays` is borrowed for the call only.

 # Safety
 If `display_count != 0`, `displays` must point to at least `display_count` readable
 [`AisdRect`] values.
 */
struct AisdPoint aisd_vd_origin_to_right(const struct AisdRect *displays, size_t display_count);

/*
 The chip's horizontal pixel ceiling from a CPU brand string (Pro/Max/Ultra → 7680, base
 Apple M → 6144, else 7680). Wraps [`virtual_display_geometry::chip_pixel_limit`].

 # Safety
 `cpu_brand` must be a valid NUL-terminated C string, or null (treated as the default).
 */
int64_t aisd_vd_chip_pixel_limit(const char *cpu_brand);

/*
 Writes the descending refresh-rate modes for a VD driven at `fps` into `rates` and returns
 the count. Wraps [`virtual_display_geometry::refresh_rates`] (always 2 or 3 values).

 Writes nothing (but still returns the needed count) if `rates` is null or `capacity` is
 smaller than the count, so a caller can size a buffer; in practice 3 slots always suffice.

 # Safety
 If non-null, `rates` must point to at least `capacity` writable `f64` values.
 */
size_t aisd_vd_refresh_rates(int64_t fps, double *rates, size_t capacity);

/*
 Encodes a caller-built [`AisdWindowGeometry`] into its wire form.

 On [`AISD_OK`], `*out` owns the buffer — release with [`crate::aisd_bytes_free`]. Returns
 [`AISD_ERR_NULL`] for a null argument or [`AISD_ERR_INVALID_ARGUMENT`] for an unknown `kind`
 / non-UTF-8 `title`.

 # Safety
 `msg` and `out` must be valid, writable pointers; a non-empty `title` inside `*msg` must
 point to that many readable bytes.
 */
AisdStatus aisd_window_geometry_encode(const struct AisdWindowGeometry *msg, struct AisdBytes *out);

/*
 Decodes a window-geometry message into `*out`.

 On [`AISD_OK`], `*out` may own a `title` buffer — release with [`aisd_window_geometry_free`].
 `data` may be null only when `len == 0`. Maps a non-finite coordinate / non-UTF-8 title /
 unknown type to [`crate::AISD_ERR_MALFORMED`] and a short body to [`crate::AISD_ERR_TRUNCATED`].

 # Safety
 `out` must be writable; if `len != 0`, `data` must point to `len` readable bytes. On a
 non-[`AISD_OK`] return `*out` is untouched; on [`AISD_OK`] it is overwritten as raw output
 WITHOUT freeing prior contents.
 */
AisdStatus aisd_window_geometry_decode(const uint8_t *data,
                                       size_t len,
                                       struct AisdWindowGeometry *out);

/*
 Releases the owned `title` buffer inside an [`AisdWindowGeometry`] and resets it to empty.
 Idempotent; the struct itself is caller-owned.

 # Safety
 `msg` must point to a writable [`AisdWindowGeometry`] previously filled by this library.
 */
void aisd_window_geometry_free(struct AisdWindowGeometry *msg);

/*
 Clamp a window of `window_w × window_h` to `display` (shrink-only) and place it at the
 display's top-left origin. Wraps [`window_placement::placement`]. Pure; never fails.
 */
struct AisdPlacement aisd_window_placement(double window_w,
                                           double window_h,
                                           struct AisdRect display);

/*
 Whether a window of `size_w × size_h` fits inside `bounds` (½-pt tolerance). Returns `1` if it
 fits, `0` otherwise. Wraps [`window_placement::fits`]. Pure; never fails.
 */
uint8_t aisd_window_fits(double size_w, double size_h, struct AisdRect bounds);

/*
 The BT.709 YCbCr→RGB coefficients for the negotiated luma range.

 `full_range != 0` ⇒ full swing (luma scale `1.0`, bias `0`), else studio/video swing (the
 current shader literals, byte-for-byte). Wraps [`ycbcr::coefficients`]. Pure; never fails.
 */
struct AisdYCbCrCoefficients aisd_ycbcr_coefficients(uint8_t full_range);

